"""
MKT Context Commentary — Jeremiah chapters 1–3
Run: python3 scripts/zc-context-jeremiah-1-3-fill.py

Source data used:
- data/interlinear/jeremiah.json
- data/translation/draft/mediating/jeremiah.json

Key decisions in this range:
- Ch 2–3 treated as a formal covenant lawsuit (rib genre): YHWH is plaintiff,
  Israel/Judah is defendant, heaven and earth are implicitly summoned as witnesses
- The marriage/adultery metaphor for the YHWH–Israel covenant is treated as a
  deliberate inversion of Baal cult fertility imagery: Baal-worship framed as
  literal adultery against Israel's true husband (YHWH)
- The Israel/Judah double indictment (3:6-11) treated in its 722-BCE historical
  context: the Northern Kingdom's deportation by Assyria is the recent precedent
  Jeremiah uses to warn Judah
- The almond-rod and boiling-pot visions (1:11-14) treated as wordplay-visions
  whose primary function is establishing prophetic authorization
- Jeremiah's call protest (1:6) compared to Moses (Exod 4:10) and Isaiah (Isa 6:5)
  as belonging to a recognized prophetic-call-resistance genre
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    """Merge new_data into existing without overwriting present entries."""
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

JER = {
  "1": {
    "2": "<p>'The word of the LORD came to him in the days of Josiah son of Amon, king of Judah, in the thirteenth year of his reign' — 627/626 BCE, approximately four years before Josiah's great reform (621 BCE, triggered by the discovery of the Torah scroll in the temple: 2 Kings 22). Jeremiah's call therefore precedes the deuteronomic reform; his entire early ministry overlaps with the reform period, making the later resumption of apostasy under Jehoiakim (609 BCE) all the more devastating. The dating formula grounds Jeremiah's words in verifiable historical time — a standard feature of eighth-and-seventh-century prophetic books that distinguishes them from timeless wisdom literature.</p>",
    "3": "<p>'It came again in the days of Jehoiakim ... continuing through the eleventh year of Zedekiah ... until Jerusalem was carried away captive in the fifth month' — the book's temporal frame spans three reigns and culminates in the Babylonian exile of 586 BCE. The 'fifth month' (Ab = July/August) is the month the first temple was destroyed (2 Kings 25:8-9), which became the annual fast of Tisha B'Av in later Judaism. Jeremiah's career thus covers Judah's entire final generation — from reform to catastrophe — making him the witness-prophet of the covenant's ultimate failure under the old structure.</p>",
    "4": "<p>'The word of the LORD came to me' — the call-vision narrative (vv. 4-19) follows the standard OT call-narrative structure: divine address → human protest → divine reassurance → sign → commission (cf. Moses: Exod 3-4; Isaiah: Isa 6; Ezekiel: Ezek 1-3; Gideon: Judg 6:11-24). The formula 'the word of the LORD came to me' (<em>wayĕhî dĕbar-Yhwh ʾēlay</em>) is Jeremiah's characteristic prophetic authorization formula, appearing over 150 times in the book. It distinguishes prophetic speech from wisdom teaching or royal decree — the authority is not learned but received.</p>",
    "5": "<p>'Before I formed you in the womb I knew you, and before you were born I consecrated you; I appointed you a prophet to the nations' — the pre-birth call is the most extreme form of prophetic election in the OT. The verb <em>yādaʿ</em> (know) here carries the relational sense of covenantal intimacy (as in Gen 18:19: 'I have known him [Abraham], so that he may direct his children'). <em>Qiddaštî</em> (I consecrated/set apart) is the dedication language used for the Nazirite vow and temple vessels — Jeremiah is consecrated as a dedicated instrument before birth. 'Prophet to the nations' (<em>lĕgôyim</em>, plural) is surprising: Jeremiah's mandate is not merely to Judah but to the international political order.</p>",
    "6": "<p>'Ah, Lord GOD! I do not know how to speak, for I am only a child' — the call-resistance follows a recognized genre. Moses: 'I am not eloquent' (Exod 4:10); Isaiah: 'I am a man of unclean lips' (Isa 6:5); Gideon: 'my clan is the weakest in Manasseh, and I am the least in my family' (Judg 6:15). The objection establishes that the prophet is not a self-appointed speaker — he is sent despite personal inadequacy, which grounds the authority in divine initiation rather than human qualification. 'I am only a child' (<em>naʿar ʾānōkî</em>) probably means 'young man' (15-20 years old if the 627 BCE date is accurate) rather than an infant, though the exact age is disputed.</p>",
    "7": "<p>'Do not say, &ldquo;I am a child,&rdquo; for you shall go to everyone I send you to' — the divine counter to the protest uses the same two elements as Exodus 3-4: the commission overrides the objection, and the 'I am with you' promise (v. 8) replaces the inadequacy. The chiastic structure is precise: 'Do not say X (I can't speak) / because Y (you shall speak / you shall go)' — the divine mandate redefines what is possible. The repetition of 'everything I command you' establishes the prophetic mandate as a delivery function: Jeremiah does not select the message but transmits it faithfully.</p>",
    "8": "<p>'Do not be afraid of them, for I am with you to rescue you, declares the LORD' — the reassurance formula 'I am with you' (<em>ʾittĕkā ʾānî</em>) is the same presence-promise given to the patriarchs (Gen 26:24; 28:15), Moses (Exod 3:12), and Joshua (Josh 1:5,9). Its appearance here situates Jeremiah in the covenant-leader succession. 'To rescue you' (<em>lĕhaṣṣîlĕkā</em>, to deliver/snatch away) anticipates the book's pattern: Jeremiah will face constant opposition, imprisonment, and assassination attempts (chs 11, 20, 26, 36-37), and YHWH's rescue will be his repeated experience.</p>",
    "9": "<p>'Then the LORD reached out his hand and touched my mouth' — the mouth-touch is the physical counterpart to the verbal commission: the divine hand places the word in the prophet's mouth. The closest parallel is Isaiah 6:6-7, where a seraph touches Isaiah's lips with a live coal and declares his guilt removed. Here the gesture is direct: no intermediary, no purification — YHWH's hand directly consecrates Jeremiah's speech organ. The superscription's 'the words of Jeremiah' (1:1) and the formula 'I have placed my words in your mouth' create a dual authorship claim: the book is Jeremiah's in form but YHWH's in content.</p>",
    "10": "<p>'I have appointed you this day over nations and kingdoms, to uproot and to tear down, to destroy and to demolish, to build and to plant' — the six-verb mandate (four destructive, two constructive) defines the character of Jeremiah's prophetic ministry. The ratio (4:2) reflects the book's dominant tone: the judgment oracles far outnumber the restoration promises, though the restoration material (chs 30-33: the 'Book of Consolation') is among the most extended in the prophets. 'Over nations and kingdoms' makes Jeremiah a geo-political prophet whose words function as divine decrees over the international order — the Babylonian invasions are the fulfillment of this mandate.</p>",
    "11": "<p>'What do you see, Jeremiah? I see a branch of an almond tree' — the vision reports follow the standard prophetic vision-dialogue form found in Amos 7-8 (the locust, fire, plumb line, summer fruit) and Zechariah 1-6 (the horses, horns, man with measuring line). The almond tree (<em>šāqēd</em>) was the first tree to blossom in spring (January/February), making it a symbol of watchful anticipation. In Hebrew, <em>šāqēd</em> (almond) creates a deliberate sound-play with <em>šōqēd</em> (watching/wakeful: v. 12), exploiting the root SQD.</p>",
    "12": "<p>'You have seen rightly, for I am watching over my word to carry it out' — the word-play: <em>šāqēd</em> (almond) : <em>šōqēd</em> (I am watching). The pun is the point of the vision: the almond-branch is not allegorical content but a mnemonic trigger for the divine watchfulness-claim. YHWH's wakeful vigilance over his announced word guarantees its fulfillment. This is a key claim in the face of prophetic skepticism: the word of judgment does not return void (Isa 55:11) — YHWH stays wakeful over it until it is enacted.</p>",
    "13": "<p>'I see a boiling pot, with its mouth turned from the north' — the boiling pot (<em>sîr nāpûaḥ</em>) facing south (i.e., its contents will spill southward out of the north) represents the impending military invasion from Babylon. The north-as-source-of-disaster was an established geographic-political reference: Assyria and Babylonia both invaded from the north (the direct east-west route across the Fertile Crescent). In the ancient imagination, the north was the direction of cosmic threat (Isa 14:13: the king of Babylon seeking 'the far north' as the mountain of the gods) as well as political danger.</p>",
    "14": "<p>'Disaster will break out from the north against all who live in this land' — the 'foe from the north' (<em>mîṣṣāpôn</em>) is one of Jeremiah's most developed themes (4:6; 6:1,22; 10:22; 13:20; 25:9). In the early chapters (1-6), the northern foe is unnamed — a deliberate rhetorical choice that maintains threat-ambiguity and maximum pressure. Scholars debate whether the early 'foe from the north' oracles referred to the Scythian raids of the late seventh century (Herodotus 1.104-106) or always to Babylon. The later identification of Babylon as YHWH's instrument (25:9: 'my servant Nebuchadnezzar') retroactively clarifies the earlier oracles.</p>",
    "15": "<p>'For see, I am summoning all the peoples of the kingdoms of the north ... They will come and will each set up his throne at the entrance to the gates of Jerusalem' — the military picture is precise: foreign kings setting their thrones at the gate meant establishing judicial authority over the conquered city (cf. Jer 39:3: the Babylonian officials sitting in the Middle Gate after the fall of Jerusalem). The gate as the seat of legal authority (Deut 21:19; Ruth 4:1-2) makes this image doubly humiliating: the foreign invaders will occupy Israel's civic-judicial space.</p>",
    "16": "<p>'I will pronounce my judgments against them for all their wickedness — they have forsaken me, burned incense to other gods' — the covenant lawsuit formula: YHWH as judge pronouncing sentence against the covenant-violating people. The three charges (forsaking YHWH / burning incense to other gods / bowing to idols) correspond to the three prohibitions of the Decalogue's first commandment complex (Exod 20:3-5). Burning incense (<em>qiṭṭēr</em>) to other gods was the most common form of popular idolatry in the ANE — incense offerings were made to Baal, Asherah, and the host of heaven (2 Kings 23:5; Jer 44:17-19).</p>",
    "17": "<p>'As for you, get yourself ready. Arise and speak to them everything I command you. Do not be terrified by them, or I will terrify you before them' — the double-terror warning is striking: if Jeremiah allows human fear to silence the divine word, YHWH will bring divine terror upon him instead. This inverts the usual prophetic reassurance: the expected formula is 'do not fear, for I am with you'; here the prophet is warned that cowardice has its own divine consequence. The word 'terrified' uses <em>ʾal-tēḥat</em> (from <em>ḥātat</em>, to be shattered/broken), the same root used for the militarily defeated and for the psychologically crushed.</p>",
    "18": "<p>'See, I have made you today a fortified city, an iron pillar, and bronze walls' — the metaphors of architectural impregnability describe the prophet's divinely sustained endurance against social opposition. A 'fortified city' (<em>ʿîr miḇṣār</em>) was the highest military designation in the ANE — a city able to withstand siege. 'Iron pillar' and 'bronze walls' add the additional images of vertical structural integrity and defensive perimeter. The prophet does not become physically invulnerable (he will be beaten, imprisoned, and thrown in a cistern) but spiritually sustained against the crushing social pressure his message will generate.</p>",
    "19": "<p>'They will fight against you, but they will not overcome you, for I am with you to rescue you, declares the LORD' — the divine-presence promise closes the call narrative as it opened it (v. 8): 'I am with you to rescue you.' The inclusio creates the call's theological frame: the entire commission (vv. 9-18) is bracketed by the presence-promise. The Jeremiah narrative (chs 26-45) will repeatedly show this promise tested: Jeremiah faces execution multiple times (26:10-11; 38:4-6), but the word 'they will not overcome you' stands throughout — not through ease but through sustained divine protection.</p>",
  },
  "2": {
    "1": "<p>'The word of the LORD came to me' — the oracular formula opens chapter 2's extended covenant lawsuit, which continues through chapter 6 (the 'foe from the north' section). The transition from the call narrative (ch 1) to the first major address follows the standard prophetic book structure: authorization (ch 1) precedes proclamation (chs 2ff.).</p>",
    "2": "<p>'I remember the devotion of your youth, the love of your bridal days, how you followed me through the wilderness' — YHWH's opening move in the lawsuit is nostalgic — he recalls the covenant's honeymoon period. The 'devotion of your youth' is <em>ḥesed nĕʿûrayik</em> — Israel's own <em>ḥesed</em> (covenant loyalty) during the wilderness period. This is the inverse of YHWH's <em>ḥesed</em> toward Israel; here Israel reciprocated. The wilderness period is idealized throughout the prophets (Hos 2:14-15; Ezek 20:10-13; Deut 32:10-11) as a time of exclusive dependence on YHWH before the land and its Canaanite temptations intervened.</p>",
    "3": "<p>'Israel was holy to the LORD, the firstfruits of his harvest; all who consumed them were held guilty' — Israel as YHWH's <em>qōdeš</em> (holy/set-apart) and <em>rēʾšît tĕbûʾātōh</em> (firstfruits of his harvest) applies the Levitical firstfruits category (Exod 23:19; Lev 23:10) to the nation itself. The firstfruits were YHWH's portion — untouchable by others; consuming them incurred guilt. This establishes the theological basis for the judgment oracles: the nations who attacked Israel attacked something consecrated to YHWH, and the consequences were divinely mandated. The passage simultaneously vindicates the covenant relationship and condemns Israel's apostasy.</p>",
    "4": "<p>'Hear the word of the LORD, O house of Jacob, all the families of Israel' — the lawsuit begins with the formal summons to hear, a standard covenant-lawsuit opening (cf. Isa 1:2: 'Hear, O heavens! Listen, O earth!'; Mic 6:1-2: 'Hear what the LORD says'). 'All the families of Israel' (<em>kol-mišpĕḥôt bêt yiśrāʾēl</em>) addresses the tribal structure of the covenant people — the lawsuit is not against individuals but against the covenant community as a corporate entity. The 'house of Jacob' phrasing connects to the ancestral covenant and situates the dispute within the long covenant history.</p>",
    "5": "<p>'What fault did your fathers find in me, that they went so far from me, following worthless idols and becoming worthless themselves?' — the covenant lawsuit's first argument: YHWH challenges the prosecution's case by demanding evidence of divine wrongdoing. The gods Israel followed are called <em>hahebel</em> (the vanity/breath/vapor) — the same word that governs Ecclesiastes ('vanity of vanities'). The word-play is incisive: those who follow breath-idols (<em>hebel</em>) become vapor-people (<em>wayehbāl</em>) themselves — the idol shapes its worshipper. The argument is: there was no legitimate reason for the defection; the gods Israel chose are ontologically inferior to the covenant partner they abandoned.</p>",
    "6": "<p>'They did not ask, Where is the LORD who brought us up out of Egypt, who led us through the wilderness?' — the wilderness is cited as the test-case of divine reliability: YHWH led Israel through 'a land of deserts and ravines, through a land of drought and deep darkness.' The rhetorical point is that Israel already has empirical evidence of YHWH's provision in the most extreme conditions imaginable. Not asking 'Where is the LORD?' represents willful theological amnesia — a failure to trace the present back to the proven historical pattern of divine faithfulness.</p>",
    "7": "<p>'I brought you into a land of plenty, to enjoy its fruit and abundance. But when you entered, you defiled my land and made my heritage loathsome' — the land-gift and land-defilement are placed in immediate sequence without transitional explanation: the gift was answered with defilement. 'My land' (<em>ʾarṣî</em>) and 'my heritage' (<em>naḥălātî</em>) assert divine ownership of Canaan that pre-exists the covenant: YHWH does not give Israel land that becomes theirs; he gives them tenancy rights in land that remains his. The defilement (<em>timmettem</em>) is the ritual-purity term — Canaanite cult practices made the land unclean in the same way they made people unclean.</p>",
    "8": "<p>'The priests did not ask, Where is the LORD? Those who deal with the law did not know me; the rulers transgressed against me; the prophets prophesied by Baal' — the comprehensive leadership indictment: all four pillars of Israelite society have failed. Priests (liturgical custodians), law-teachers/scribes (<em>tōpĕśê hattôrāh</em>), rulers (<em>rōʿîm</em>, shepherds/kings), and prophets — each group identified by their function and indicted for its failure. The prophets prophesying by Baal is a specific historical reference: the Baal cult had a prophetic dimension (450 prophets of Baal: 1 Kings 18:19), and false prophets within Israel had adopted Baal-prophetic practices.</p>",
    "9": "<p>'Therefore I will bring charges against you again, declares the LORD, and against your grandchildren will I bring charges' — the lawsuit (<em>rîb</em>) will continue generationally. The covenant-curse framework of Deuteronomy 5:9 (YHWH 'visiting the iniquity of the fathers upon the children to the third and fourth generation') applies here not merely as punishment but as prosecution: the transgenerational accountability of the covenant makes each generation responsible both for its own sin and for the legacy of its predecessors.</p>",
    "10": "<p>'Cross to the shores of Cyprus and look; send to Kedar and examine carefully' — Cyprus (Kittim, the western Mediterranean) and Kedar (northern Arabia, the east) form a geographic merism covering the known world's extremes. Jeremiah invites his audience to conduct a comparative religion survey: examine the ends of the earth for evidence of any nation abandoning its gods. The argument is from the bizarre: even pagan nations with manifestly inferior, non-existent gods maintain covenant loyalty to them. Israel's defection from the living God is more than religious failure — it is a sociological anomaly.</p>",
    "11": "<p>'Has any nation changed its gods, even though they are not real gods? But my people have exchanged their glory for things that are worthless' — the irony is acute: nations who worship genuinely inferior deities stay loyal to them; Israel, who has the genuinely superior covenant partner, has traded up for inferiors. 'My glory' (<em>kĕbôdô</em>, his glory — the LXX reads 'their glory') refers to YHWH himself as the source of Israel's honor and status among nations. To exchange him for Baals is not merely a religious mistake but a catastrophic status-inversion: trading patron-position with the creator for vassalage to powerless regional spirits.</p>",
    "12": "<p>'Be appalled at this, O heavens; shudder with great horror, declares the LORD' — the heavens are called as shocked witnesses, an expansion of the cosmic-witness role in the covenant lawsuit. The imperative to the heavens to be appalled (<em>šōmmû haššāmayim</em>) is stronger than the Deuteronomic witness formula (Deut 32:1: 'Listen, O heavens') — here the heavens are not merely called to testify but to recoil in horror. The prophetic imagination treats the cosmos as morally responsive: creation itself is outraged by covenant violation.</p>",
    "13": "<p>'My people have committed two evils: they have abandoned me, the spring of living water, and dug their own cisterns — cracked cisterns that cannot hold water' — the water-source metaphor is one of the most powerful in Jeremiah. YHWH as <em>mĕqôr mayim ḥayyîm</em> (spring of living water) — an active, flowing, fresh source — is set against man-made <em>bōrôt</em> (cisterns), and specifically cracked ones. In Palestine's semi-arid climate, the cistern was the alternative to the spring: a rock-hewn reservoir that collected and held rainwater. A cracked cistern cannot hold what it collects — it is not even a reliable artificial substitute for the natural spring. The two failures are progressive: first abandoning the real, then trusting the inadequate.</p>",
    "14": "<p>'Is Israel a slave? Was he born into slavery? Then why has he become plunder?' — the rhetorical questions probe the cause of Israel's subjugation. The assumed answer is 'no' — Israel is not a natural slave class; the covenant relationship with YHWH granted them the status of YHWH's firstborn son (Exod 4:22). The rhetorical logic: if Israel is not naturally enslaved, something must have caused the current status of being plundered by enemies. The answer will come in v. 17: they brought it on themselves. The 'plunder' (<em>lĕbaz</em>) anticipates the Assyrian and Babylonian deportations already underway for the northern kingdom and coming for Judah.</p>",
    "15": "<p>'Young lions have roared against him and growled; they have laid his land waste' — the young lions (<em>kĕpîrîm</em>) are a standard ANE metaphor for devastating military invaders (Nah 2:11-12; Isa 5:29; Ps 34:10 uses the same term for powerful predators). The devastation description — cities burned, land emptied — corresponds to the Assyrian campaign against the Northern Kingdom (734-722 BCE) and to the Babylonian campaigns against Judah (605-586 BCE). Jeremiah uses the image as present-tense warning: this is happening now to Israel, and it will happen to Judah unless the trajectory changes.</p>",
    "16": "<p>'The people of Memphis and Tahpanhes have shaved the top of your head' — Memphis (<em>Nōp</em>) and Tahpanhes (<em>Taḥpanḥēs</em>, the modern Tell Defenna in the Nile Delta) are Egyptian cities, representing Egypt as Judah's unreliable political ally. 'Shaving the top of the head' is a humiliation idiom — the Egyptians have degraded rather than protected Judah. The critique points to Josiah's alliance politics: his death at Megiddo (609 BCE) came while trying to block Pharaoh Necho's march to Assyria, suggesting pro-Egyptian factionalism in the Judean court that Jeremiah consistently opposed. Egypt will fail Judah at the critical moment.</p>",
    "17": "<p>'Have you not brought this on yourself by forsaking the LORD your God when he led you on the way?' — the self-causation of disaster is the covenant's built-in logic: the curses of Deuteronomy 28 are not arbitrary divine punishment but the natural consequence of choosing covenant violation. 'On the way' (<em>bĕdērek</em>) may refer to the Exodus journey — the moment when YHWH demonstrated faithful guidance (cf. v. 6's wilderness reference) and Israel responded with faithlessness. The wilderness testing-and-failure pattern (Exod 16-17; Num 11-21) is the historical paradigm for the ongoing pattern Jeremiah is diagnosing.</p>",
    "18": "<p>'And now why go down to Egypt to drink from the waters of the Nile? Or why go to Assyria to drink from the Euphrates?' — Egypt (Nile) and Assyria (Euphrates) represent the two great imperial powers between which Judah's court played its political game. The 'drinking water' metaphor for political alliance reflects the ANE patron-client system: a small state 'drinking' from a great power's river means depending on its patronage, military support, and political protection. Jeremiah consistently opposed both Egyptian and Babylonian alliance as alternatives to covenant trust in YHWH — the anti-treaty theology runs through his ministry (27:5-8).</p>",
    "19": "<p>'Your own wickedness will punish you, and your turning away will rebuke you' — <em>tĕyassĕrĕkā rāʿātēk</em>: the punishment is internal to the sin, not externally applied as separate divine action. This is the covenant's self-executing logic: abandoning the spring of living water creates its own punishment (thirst); turning from the covenant partner who provides security creates vulnerability to the enemies you sought protection from. 'Know and see that it is evil and bitter to forsake the LORD' — the <em>daʿ wĕrĕʾî</em> (know and see) is an invitation to empirical investigation: look at what has happened, and understand the causality.</p>",
    "20": "<p>'For long ago I broke your yoke and tore off your chains. But you said, &ldquo;I will not serve!&rdquo; And on every high hill and under every spreading tree you gave yourself like a prostitute' — the yoke-and-chains broken are the Exodus liberation: YHWH's founding act was precisely to free Israel from forced service to Pharaoh. Israel's response was to declare 'I will not serve!' — the same verb <em>ʿābad</em> (serve) used for both Egyptian slavery and covenant worship. The irony: freed from servitude, Israel voluntarily enslaves itself again to Baal at every high hill and spreading tree. The high places (<em>bāmôt</em>) and sacred trees (<em>ʾayyil raʿănan</em>) were the standard Canaanite cult-installation locations.</p>",
    "21": "<p>'I had planted you as a choice vine, of pure and wholesome seed. How then have you turned against me into the wild shoots of a foreign vine?' — the choice-vine (<em>śōrēq</em>, the finest variety of grape) metaphor pictures YHWH as the careful vinedresser who planted Israel with genetic precision. The transformation into a <em>gepen nŏkrîyyāh</em> (foreign vine, degenerate shoots) represents a categorical degradation — not merely poor performance but a change in essential nature. Isaiah 5:1-7 develops the same vine-owner metaphor at length; Jesus's 'I am the true vine' (John 15:1) takes up the same imagery with the claim to be what Israel failed to be.</p>",
    "22": "<p>'Even if you scrubbed yourself with lye and used much soap, the stain of your guilt would still be before me' — the stain (<em>nikĕtām ʿăwōnēk</em>) that resists all ritual purification agents is a picture of guilt that has become structural rather than transactional. Natron-lye (<em>bōrit</em>) and soap (<em>neter</em>) were the standard ANE cleaning agents; the point is that the most powerful physical purification methods cannot reach this depth of defilement. Psalm 51:7 ('Wash me, and I shall be whiter than snow') implicitly acknowledges the same problem — only divine action can accomplish what human purification cannot.</p>",
    "23": "<p>'How can you say, &ldquo;I am not defiled, I have not chased after the Baals&rdquo;? Look at your tracks in the valley' — the valley (<em>gĕyʾ</em>) probably refers to the Valley of Ben Hinnom (Topheth) south of Jerusalem, where child sacrifice to Molech was practiced (Jer 7:31; 19:5-6; 2 Kings 23:10). The 'tracks' (<em>dĕrākayik baggāyʾ</em>) are the evidence that refutes the denial: the physical places of cultic activity are visible. The 'swift young camel' simile pictures frantic, undirected motion — the compulsive energy of religious syncretism that lacks the purposeful direction of covenant loyalty.</p>",
    "24": "<p>'Like a wild donkey at home in the desert, sniffing the wind in her craving — who can hold her back when she is in heat?' — the wild-donkey-in-heat is an extended metaphor for the uncontrollable appetite of Israel's idolatry. The simile is deliberately crude: the most ungovernable animal drive (a female animal in estrus) is used to picture Israel's compulsive attraction to foreign cults. The point is that no human intervention can restrain it — 'all who look for her need not tire themselves; they will find her in her mating season.' Israel's unfaithfulness is not a momentary lapse but a structural addiction.</p>",
    "25": "<p>'Keep your feet from going bare and your throat from being dry. But you said, &ldquo;It is hopeless! I love other gods, and after them I will go&rdquo;' — the warning about bare feet and a dry throat is metaphorical: running after lovers leads to exhaustion. YHWH's counsel is to stop the running before it leads to ruin. But the response ('It is hopeless!': <em>nôʾāš</em>, despair) is a declaration of covenant abandonment — not ignorance or confusion, but a deliberate choice to declare the covenant unworkable and pursue the alternative. This is the moral low point of the chapter: the explicit, knowing decision to abandon YHWH for other gods.</p>",
    "26": "<p>'As a thief is put to shame when caught, so the house of Israel will be shamed — they, their kings, their officials, their priests, and their prophets' — the shame-when-caught image applies to the whole leadership hierarchy listed in the same order as v. 8. The shame (<em>bōšet</em>) is a comprehensive covenant-consequence: honor was the expected outcome of covenant faithfulness (Deut 26:19: YHWH will make Israel 'high above all nations'); shame is the consequence of its reversal. The list king-officials-priests-prophets is the same leadership structure that will fail during the siege of Jerusalem (Lam 4:12-16).</p>",
    "27": "<p>'They say to a tree, &ldquo;You are my father,&rdquo; and to a stone, &ldquo;You gave me birth&rdquo;' — the tree-and-stone worship targets the Asherah cult and the standing stones (<em>maṣṣēbāh</em>) of Canaanite religion. The Asherah was a wooden pole or stylized tree associated with the goddess Asherah, consort of El; 'you are my father' addressed to the tree represents a fundamental reordering of the divine family: YHWH (the true Father: Isa 63:16; 64:8) is displaced by a fertility goddess's wooden symbol. 'They have turned their backs to me and not their faces. Yet in the time of their trouble they will cry, Rise up and save us!' — the YHWH-rejection is reversed only in crisis, reflecting the complaint-and-rescue pattern of the Judges cycles.</p>",
    "28": "<p>'But where are the gods you made for yourself? Let them rise up, if they can rescue you in the time of your trouble — for you have as many gods as you have cities, O Judah' — the challenge-to-the-idol motif (cf. Isa 41:21-24; 44:9-20) invites empirical evaluation: if the Baals are real, let them act. The 'as many gods as cities' formula (<em>kĕmispar ʿārêk hāyû ʾĕlōhêkā</em>) points to the local Baal-shrines at each town's high place — each city had its local Baal, and each Baal-shrine represented a separate defection from the covenant. The multiplication of worship sites was both the symptom and the intensification of the apostasy.</p>",
    "29": "<p>'Why do you bring a complaint against me? You have all rebelled against me, declares the LORD' — the covenant lawsuit has an unexpected reversal: Israel might bring a counter-complaint that YHWH's punishment was excessive, but YHWH preempts it by pointing out that universal rebellion (<em>kullĕkem pĕšaʿtem bî</em>) disqualifies any counter-claim. The <em>rîb</em> (lawsuit) runs in one direction only when the evidence of violation is total. The legal frame makes Israel's potential objection frivolous rather than substantive.</p>",
    "30": "<p>'I have struck your people in vain; they accepted no correction. Your own sword has consumed your prophets like a ravaging lion' — the divine discipline (<em>hikkîtî ʾet-bĕnêkem lĕšāwĕʾ</em>) has already occurred and failed. The history of discipline without repentance reaches its logical conclusion: when correction produces no correction, escalated consequences follow. 'Your own sword has consumed your prophets like a ravaging lion' refers to the persecution of true prophets by the establishment — a pattern evidenced in the murder of the prophet Uriah (Jer 26:20-23) and the consistent opposition to Jeremiah himself.</p>",
    "31": "<p>'O generation, take heed of the word of the LORD: Have I been a desert to Israel or a land of thick darkness? Why do my people say, &ldquo;We are free; we will come to you no more&rdquo;?' — YHWH as defendant: the rhetorical question invites the people to evaluate whether the covenant relationship has been oppressive or beneficial. A desert (<em>midbār</em>) and thick darkness (<em>maḥšāk</em>) are the conditions of danger and divine absence; YHWH asks whether his governance has been experienced as that. 'We are free' (<em>rādnû</em>, we have roamed free) is the people's claim that covenant obligation was servitude — a claim YHWH challenges by pointing to the actual benefits of the relationship.</p>",
    "32": "<p>'Does a young woman forget her jewelry, or a bride her wedding attire? Yet my people have forgotten me — for more days than can be counted' — the comparison to a bride's accessories (<em>ʿădî</em>, ornaments; <em>kišrōtêhā</em>, wedding sash or bridal attire) illustrates the improbability of Israel's forgetfulness. A bride's ornaments are her most prized possessions, never forgotten even momentarily. Israel's forgetting of YHWH across countless days is thus more extreme than the most unthinkable human forgetfulness. The bride imagery also anticipates the marriage metaphor of chapter 3 and the larger prophetic tradition of YHWH as Israel's husband (Hos 2; Ezek 16).</p>",
    "33": "<p>'How skilled you are at pursuing love; you have become expert enough to teach the wicked your ways' — the ironic compliment: Israel has become so proficient at idolatrous religious practice that it has exceeded the Canaanites ('the wicked') in expertise. The 'pursuing love' is <em>baqēš ʾahăbāh</em> — seeking lovers, the standard idiom for religious prostitution at cult shrines. The reversal is complete: Israel, called to teach the nations covenantal wisdom (Deut 4:6-8: 'this is your wisdom in the sight of the peoples'), has become a master-teacher in the practice of covenant violation.</p>",
    "34": "<p>'On your garments is found the lifeblood of innocent poor people — you did not catch them breaking in; it is on all these' — the blood of the innocent poor is visible evidence of social injustice that Jeremiah adds to the religious indictment. Unlike a thief caught breaking in (Exod 22:2: not guilty for killing a burglar), the blood on Israel's garments comes from unsuspecting innocents — premeditated violence against the vulnerable. Amos (2:6-8; 5:11-12) and Isaiah (1:21-23; 3:14-15) develop the same connection between idolatry and social injustice: false religion and exploitation of the poor are two aspects of the same covenant failure.</p>",
    "35": "<p>'Yet you say, &ldquo;I am innocent; surely his anger has turned from me.&rdquo; But I will bring judgment against you because you say, &ldquo;I have not sinned&rdquo;' — the self-exculpation (<em>niqqêtî</em>, I am clean/innocent) while the blood of the poor is visible on the garments is the most extreme moral blindness in the chapter. The denial of sin (<em>lōʾ ḥāṭāʾtî</em>) is not ignorance but a deliberate refusal to acknowledge guilt. In the covenant framework, this refusal itself becomes grounds for judgment — it represents the hardening of the heart that makes repentance structurally impossible without divine intervention (the heart-circumcision of Deut 30:6).</p>",
    "36": "<p>'Why do you rush about so much, changing course? You will be disappointed by Egypt just as you were disappointed by Assyria' — the political instability — rushing between Egypt and Assyria as alternative patrons — mirrors the religious instability of chasing different Baals. Both Jeremiah (37:5-10) and the broader DH tradition (2 Kings 18-19: Hezekiah's temptation to rely on Egypt) treat pro-Egyptian policy as covenant unfaithfulness: it demonstrates that the court trusts imperial military power rather than YHWH's provision. Egypt's failure at Carchemish (605 BCE, Jer 46:2) and at the siege of Jerusalem (37:7-8) will fulfill this prediction.</p>",
    "37": "<p>'You will leave Egypt too with your hands on your head in defeat, for the LORD has rejected the ones you are trusting, and you will not succeed through them' — hands on the head was the posture of mourning and defeat (2 Sam 13:19; cf. Lam 2:10). The prediction is historically fulfilled in Jeremiah 37:5-8: Pharaoh's army came out of Egypt and withdrew when faced by the Babylonians, leaving Jerusalem without the Egyptian relief force. The 'LORD has rejected' (<em>mēʾas Yhwh</em>) the Egyptian alliance means that YHWH's covenantal opposition to the substitution of Egyptian trust for covenant trust is active: the alliance is not merely ineffective but divinely opposed.</p>",
  },
  "3": {
    "1": "<p>'It is said: If a man divorces his wife and she goes and marries another, can he take her back? Would not the land be totally defiled?' — Jeremiah applies the divorce-and-remarriage law of Deuteronomy 24:1-4 to the YHWH-Israel relationship. The Deuteronomic law prohibited a first husband from taking back a wife who had remarried after the divorce — doing so would 'defile the land.' Jeremiah's application makes the logic striking: by the standard law, Israel's worship of other gods (marriage to other lovers) has permanently disqualified her from returning to YHWH. The 'yet return to me' at the end of the verse is theologically extraordinary — YHWH is offering what the law explicitly forbids, demonstrating that his covenant grace exceeds the law's terms.</p>",
    "2": "<p>'Raise your eyes to the bare hilltops and look — is there any place you have not been violated?' — the <em>šĕpāyim</em> (bare hills, treeless heights) were the standard Canaanite high-place locations (cf. 2:20: 'every high hill and under every spreading tree'). The violation (<em>šikkabta</em>) imagery combines the sexual/idolatrous register: the high places were sites of cult prostitution as well as Baal sacrifice. 'Sitting by the roads waiting for lovers, like a nomad lurking in the desert' continues the prostitution metaphor — Israel did not merely passively participate in Canaanite cult but actively sought it out.</p>",
    "3": "<p>'Therefore the rain has been withheld, and the spring rain has not come' — the withheld rain is the covenant curse of Deuteronomy 28:23-24 ('the sky above you will be bronze, the earth below you iron; the LORD will turn the rain of your country into dust and powder'). Rain in Palestine was the primary form of agricultural providence — almost entirely rain-fed, the land depended on the early (October-November) and latter (April-May) rains. Baal was specifically the storm and fertility deity; the irony is that worshipping Baal for rain produced drought — YHWH, not Baal, controls the rain (1 Kings 18:1: YHWH ends the drought when Baal worship is confronted at Carmel).</p>",
    "4": "<p>'Have you not just been calling out to me, &ldquo;My Father, you are my closest companion from my youth&rdquo;?' — the appeal to divine fatherhood in the midst of ongoing apostasy is called out as hypocrisy. The 'my Father' (<em>ʾābî</em>) invocation acknowledges the fundamental covenant relationship (YHWH as Father: Deut 32:6; Isa 63:16; 64:8) while the behavior contradicts the filial relationship it claims. The tension between the genuine need for divine paternal care and the unwillingness to actually live as a covenant child is the same dynamic Jesus addresses in the 'Lord, Lord' sayings (Matt 7:21).</p>",
    "5": "<p>'Will he be angry forever? Will he stay angry to the end? But see — you have spoken, and you have done all the evil you could' — the rhetorical question expects the answer 'of course not; his anger will pass' — a presumption on the divine mercy that is then punctured by the second clause. The people use the correct theological data (YHWH's anger does not last forever: Ps 30:5; 103:9) to excuse continued sin, without acknowledging that the prerequisite for the anger's passing is repentance, not simply the passage of time. Jeremiah punctures the false comfort: 'you have done all the evil you could' — the sin is not isolated behavior but comprehensive maximizing of wickedness.</p>",
    "6": "<p>'The LORD said to me in the days of King Josiah: Have you seen what faithless Israel has done? She has gone up to every high mountain and under every spreading tree and committed adultery there' — the historical flashback to Josiah's reign frames the Israel-Judah comparison. The Northern Kingdom fell to Assyria in 722 BCE under Sargon II, approximately ninety years before Jeremiah's call; Josiah is attempting to reform Judah during the period of Assyrian weakness. 'Faithless Israel' (<em>yiśrāʾēl mĕšûbāh</em>, apostate/turned-away Israel) is the Northern Kingdom personified as a woman — the feminine personification of national entities was common throughout ANE literature (Babylon, Tyre, Jerusalem: Ezek 16; 23; Isa 23; Rev 17-18).</p>",
    "7": "<p>'I said, after she had done all this, &ldquo;Return to me,&rdquo; but she did not return. Then her unfaithful sister Judah saw it' — YHWH's call to return (<em>šûbî</em>) was extended to the Northern Kingdom before its fall — a historical reference to the prophetic mission of Hosea, Amos, and others. The failure to return triggered the Assyrian exile. But this very event was witnessed by the Southern Kingdom, Judah — 'her unfaithful sister' (<em>ʾăḥôtāh bôgĕdāh yĕhûdāh</em>) — which should have learned from the northern catastrophe. The sisters motif is developed at length in Ezekiel 23 (Oholah and Oholibah).</p>",
    "8": "<p>'I saw that because faithless Israel had committed adultery, I had sent her away and given her a certificate of divorce; yet her unfaithful sister Judah had no fear, but went and became a prostitute too' — YHWH explicitly describes the Assyrian exile as a 'certificate of divorce' given to Israel — applying the Deuteronomy 24 framework to historical events. The theological move is significant: the exile is not raw power politics but a covenant legal action with a document to prove it. Judah's failure to fear the same consequence represents a willful disregard of the legal-historical precedent already set before her eyes.</p>",
    "9": "<p>'She defiled the land by the brazen ease of her prostitution, committing adultery with stones and wooden posts' — stones (<em>ʾāben</em>) and wooden posts (<em>ʿēṣ</em>) are the standing stones (<em>maṣṣēbôt</em>) and Asherah poles that populated every Canaanite high place. The 'brazen ease' (<em>miqqōl zĕnûtāh</em>, from the sound/lightness of her prostitution) suggests that Judah's cult syncretism was casual, routine, unremarkable — not even experienced as transgression. Josiah's reform (2 Kings 23:4-15) involved specifically the physical removal of these objects from the high places, the temple, and the surrounding territory.</p>",
    "10": "<p>'In spite of all this, Judah, her unfaithful sister, did not return to me with all her heart — only in pretense, declares the LORD' — the critique of Josiah's reform as 'pretense' (<em>bišeqer</em>, in falsehood/deception) is a striking assessment of one of the most comprehensive covenant-renewal efforts in Judah's history. The external reform — destroying high places, reinstituting Passover, reading the Torah — was real and significant; but it did not penetrate to the popular heart. Josiah's reform was royal and top-down; the popular religion reasserted itself immediately after his death (610-609 BCE), as evidenced by the rapid apostasy under Jehoiakim.</p>",
    "11": "<p>'The LORD said to me: Faithless Israel has shown herself more in the right than unfaithful Judah' — the comparative judgment is shocking: the Northern Kingdom, which received the judgment of exile for its sins, is declared more righteous than Judah, which had the precedent of Israel's punishment before it and sinned anyway. Sin with full historical warning is more culpable than sin without it. This is the logic Jesus applies in Luke 12:47-48 ('the servant who knew the master's will and did not act accordingly will be beaten with many blows') — greater knowledge creates greater accountability.</p>",
    "12": "<p>'Go and proclaim this to the north: &ldquo;Return, O faithless Israel,&rdquo; declares the LORD; &ldquo;I will not look on you in anger, for I am faithful in love&rdquo;' — the call to northern Israel to return represents a remarkable extension of the covenant offer beyond the political boundary of the Assyrian-held territory. 'Faithful in love' (<em>ḥāsîd ʾānî</em>) — YHWH identifies himself by his covenant <em>ḥesed</em>, the same quality he recalled in Israel's early faithfulness (2:2: <em>ḥesed nĕʿûrayik</em>). The restoration offer is grounded in YHWH's own character, not in Israel's improved behavior. This promise seeds the eschatological northern-kingdom-return of vv. 18 and Ezekiel 37:15-22 (the two sticks).</p>",
    "13": "<p>'Only acknowledge your guilt — that you have rebelled against the LORD your God and given yourself to foreign lovers under every spreading tree' — the single condition for the return offer is <em>raq dĕʿî ʾawōnēk</em> — only acknowledge/know your iniquity. Not 'perform these rituals' or 'complete this penance' but simple honest acknowledgment of the covenant violation. The spreading-tree mention points to the Asherah-cult location again (cf. 2:20; 3:6). The condition of confession before restoration is the same structure as 1 John 1:9 ('If we confess our sins, he is faithful and just to forgive us').</p>",
    "14": "<p>'Return, faithless children, declares the LORD, for I am your husband' — <em>baʿaltî bākem</em>: 'I have become master/husband over you' — the <em>baʿal</em> term for husband is deliberately chosen. Israel has been running after the Baals; YHWH claims to be the true <em>baʿal</em> (husband) they are deserting for his name's counterfeit. The one-from-a-city and two-from-a-family gathering to Zion is a picture of the eschatological remnant ingathering — small numbers surviving the judgment who will become the seed of restoration (cf. Isa 1:9; Rom 9:29).</p>",
    "15": "<p>'I will give you shepherds after my own heart, who will lead you with knowledge and wisdom' — the promised shepherds (<em>rōʿîm</em>) contrast with the failed kings-as-shepherds of Israel's history. The phrase 'after my own heart' (<em>kĕlibbî</em>) echoes the description of David (1 Sam 13:14; Acts 13:22) — the ideal covenant king. The promise anticipates the messianic shepherd of Jeremiah 23:5-6 ('a righteous branch' of David), Ezekiel 34:23-24 (David as the one shepherd), and Jesus's 'I am the good shepherd' (John 10:11-14).</p>",
    "16": "<p>'When you have become numerous and multiplied in the land in those days ... no one will say any longer, &ldquo;The ark of the covenant of the LORD.&rdquo; It will not come to mind' — the promise that the ark will be forgotten in the restoration era is one of the most striking eschatological statements in the OT. The ark (<em>ʾărôn bĕrît-Yhwh</em>) was the central covenant symbol of the First Temple; its predicted redundancy does not mean the covenant dissolves but that the new covenant relationship will so completely internalize what the ark represented that no external symbol will be needed. This anticipates the 'no temple needed' vision of Revelation 21:22 ('I did not see a temple in the city, because the Lord God Almighty and the Lamb are its temple').</p>",
    "17": "<p>'At that time Jerusalem will be called the throne of the LORD, and all nations will gather to it, to honor the name of the LORD in Jerusalem' — the eschatological Jerusalem as the throne of YHWH (replacing the ark as the locus of the divine presence) and as the gathering-point for all nations is one of the major prophetic themes (Isa 2:2-4; 60:1-5; Mic 4:1-3; Zech 14:16-17). The phrase 'no longer follow the stubborn inclination of their evil hearts' (<em>šĕrîrût libbām hārāʿ</em>) echoes Deuteronomy's consistent diagnosis of Israel's problem (Deut 29:18; 31:21) — the eschatological gathering reverses the internal obstruction that covenant violation demonstrated.</p>",
    "18": "<p>'In those days the house of Judah will join the house of Israel, and together they will come from the northern land to the land I gave your ancestors' — the Judah-Israel reunion is one of the consistent promises of the restoration oracles: Ezekiel 37:15-22 (the two sticks joined), Hosea 1:11, Isaiah 11:12-13. The political division of the kingdom (931 BCE under Rehoboam: 1 Kings 12) is treated as a reversible consequence of covenant failure, not a permanent ethnic-tribal reality. 'From the northern land' is the Assyrian/Babylonian exile direction — both kingdoms will return from the northeast.</p>",
    "19": "<p>'I had thought, &ldquo;How gladly I would treat you as my children and give you a desirable land, the most beautiful inheritance among the nations&rdquo;' — YHWH's lament reflects genuine divine pathos: the conditional is retrospective, describing an unfulfilled plan. The 'most beautiful inheritance among the nations' (<em>naḥălat ṣĕbî ṣĕbāʾôt gôyim</em>) is a high designation for the land — 'the glory of all nations' (cf. Ezek 20:6,15). The divine expectation ('I had thought you would call me &ldquo;My Father&rdquo;') is disappointed — the father-child relationship is a covenant category that Israel's behavior has denied while the covenant formally maintained it.</p>",
    "20": "<p>'But like a woman who is unfaithful to her husband, you have been unfaithful to me, O house of Israel, declares the LORD' — the marriage metaphor for the covenant is most fully developed in Hosea 2, Ezekiel 16, and Ezekiel 23, but Jeremiah's deployment here is similarly devastating: the normal social category of infidelity (<em>bāgadāh</em>, acting treacherously) is applied to the cosmic relationship. The feminine address ('O house of Israel') maintains the personification of the nation as wife across both kingdoms — both the formally divorced northern wife and the more culpable southern wife are addressed together.</p>",
    "21": "<p>'A cry is heard on the bare hilltops — the weeping and pleading of the children of Israel — because they have perverted their ways and forgotten the LORD their God' — the sound from the high places is now weeping rather than the orgiastic cult-noise of Baal worship. Whether this is a prophetic anticipation of exile-lamentation or a liturgical response within the oracle structure is debated. The parallelism is deliberate: the high places were where Israel sinned (2:20; 3:2,6); the high places are now the sites of their mourning. The lamentation motif connects to the penitential response that follows in vv. 22-25.</p>",
    "22": "<p>'Return, faithless children, and I will heal your faithlessness. &ldquo;Here we are — we come to you, for you are the LORD our God&rdquo;' — the call-and-response structure: YHWH's invitation to return is immediately answered by a congregational affirmation. Whether this is a liturgical formula (like a priestly call-and-response in a covenant renewal ceremony) or a prophetic ideal response is unclear, but its placement here suggests Jeremiah is modeling the correct penitential answer to YHWH's invitation. 'I will heal your faithlessness' (<em>ʾerpāʾ mĕšûbōtêkem</em>) — YHWH's healing of the apostasy-wound is more than forgiveness; it is therapeutic restoration of the capacity for covenant loyalty.</p>",
    "23": "<p>'Surely the commotion on the hills and mountains is a delusion; surely in the LORD our God is the salvation of Israel' — the penitential confession explicitly repudiates the high-place worship. The 'commotion' (<em>šāwĕʾ</em>, noise/emptiness) on the hills is the Baal cult activity that was supposed to produce rain, fertility, and security but is now acknowledged as deceptive. 'Surely in the LORD our God is the salvation of Israel' — the confession of exclusive reliance on YHWH is the covenant-loyalty declaration that the apostasy had denied.</p>",
    "24": "<p>'For the shameful thing has consumed from our youth what our fathers worked for — their flocks and herds, their sons and daughters' — the 'shameful thing' (<em>bōšet</em>) is a polemical term for Baal, found in compound names like Ish-bosheth (man of shame, where Baal has been replaced with Bosheth: 2 Sam 2:8; cf. 1 Chr 8:33 'Eshbaal'). Hosea 9:10 uses the same substitution. The confession acknowledges that Baal worship has literally consumed the agricultural and human resources of the nation — the flocks and herds promised to covenant faithfulness (Deut 28:4) have been destroyed by the very cult that was supposed to produce fertility.</p>",
    "25": "<p>'Let us lie down in our shame, for our dishonor covers us; for we have sinned against the LORD our God, both we and our fathers, from our youth until today, and we have not obeyed the voice of the LORD our God' — the penitential confession is comprehensive: personal ('we have sinned'), historical ('both we and our fathers'), and temporal ('from our youth until today'). Lying down in shame is the posture of total humiliation — the opposite of the lifted head that YHWH's blessing was supposed to produce (Deut 28:13: YHWH will make you the head, not the tail). The phrase 'not obeyed the voice of the LORD our God' is the summary of covenant violation that runs through Deuteronomy and the DH (Deut 28:15,45; Jer 7:28; 42:21; 44:23).</p>",
  },
}

def main():
    existing = load_comm('mkt-context', 'jeremiah')
    merge_comm(existing, JER)
    save_comm('mkt-context', 'jeremiah', existing)
    il = json.loads((ROOT / 'data/interlinear/jeremiah.json').read_text())
    out = json.loads((ROOT / 'data/commentary/mkt-context/jeremiah.json').read_text())
    all_ok = True
    for ch in range(1, 4):
        ck = str(ch)
        missing = [v for v in il.get(ck, {}) if v not in out.get(ck, {})]
        if missing:
            print(f'  ch {ch} MISSING: {missing}')
            all_ok = False
        else:
            print(f'  ch {ch}: OK ({len(il.get(ck, {}))} verses)')
    if all_ok:
        print('All verses present ✓')

if __name__ == '__main__':
    main()
